-- ============================================================-- 删除文档上传演示页面菜单-- 版本: v1.0-- 说明: 文档上传功能已合并到文件浏览器，删除独立菜单-- ============================================================-- 将文档上传菜单设为隐藏（visible='1' 表示隐藏）UPDATE sys_menu SET visible = '1' WHERE menu_id = '2001';

-- 或者彻底删除（如需保留历史记录则使用上面的隐藏方案）-- DELETE FROM sys_menu WHERE menu_id = '2001';